function solve(nums, queries) {
    class FenwickTree {
        constructor(size) {
            this.n = size;
            this.tree = new Array(this.n + 1).fill(0);
        }

        update(index, delta) {
            while (index <= this.n) {
                this.tree[index] += delta;
                index += index & -index;
            }
        }

        query(index) {
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }

        rangeQuery(l, r) {
            return this.query(r + 1) - this.query(l);
        }
    }

    const n = nums.length;
    const maxDepth = 5;
    const ft = new Array(maxDepth + 1).fill(0).map(() => new FenwickTree(n));

    function computeDepth(x) {
        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = countSetBits(current);
            depth++;
        }
        return depth;
    }

    function countSetBits(x) {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    for (let i = 0; i < n; i++) {
        const x = nums[i];
        const depth = computeDepth(x);
        if (depth >= 0 && depth <= maxDepth) {
            ft[depth].update(i + 1, 1);
        }
    }

    const answer = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const [_, l, r, k] = q;
            const count = ft[k].rangeQuery(l, r);
            answer.push(count);
        } else {
            const [_, idx, val] = q;
            const oldVal = nums[idx];
            const oldDepth = computeDepth(oldVal);
            if (oldDepth >= 0 && oldDepth <= maxDepth) {
                ft[oldDepth].update(idx + 1, -1);
            }
            nums[idx] = val;
            const newDepth = computeDepth(val);
            if (newDepth >= 0 && newDepth <= maxDepth) {
                ft[newDepth].update(idx + 1, 1);
            }
        }
    }

    return answer;
}

